// RAKITRAKATRA POLYGON - FIXED v1.0
(function(){
  var R = window.Rakitrakatra || {};
  if(typeof window.Rakitrakatra === 'undefined') window.Rakitrakatra = R;
  
  R.Polygon = function(kianja, points, opts){
    opts = opts || {};
    this.kianja = kianja;
    this.points = points || [{x:0,y:0},{x:100,y:0},{x:100,y:100},{x:0,y:100}];
    this.x = opts.x || 0;
    this.y = opts.y || 0;
    this.loko = opts.loko || '#8a2be2';
    this.fill = opts.fill !== false;
    this.stroke = opts.stroke || '#00ffff';
    this.lineWidth = opts.lineWidth || 2;
    this.sakany = 100;
    this.haavony = 100;
    
    // Calculate bounds
    var minX=Infinity, minY=Infinity, maxX=-Infinity, maxY=-Infinity;
    this.points.forEach(function(p){
      if(p.x < minX) minX = p.x;
      if(p.y < minY) minY = p.y;
      if(p.x > maxX) maxX = p.x;
      if(p.y > maxY) maxY = p.y;
    });
    this.sakany = maxX - minX;
    this.haavony = maxY - minY;
    
    if(kianja && kianja.zavatra) kianja.zavatra.push(this);
    console.log('✅ Polygon loaded with', this.points.length, 'points');
  };
  
  R.Polygon.prototype.slice = function(x1,y1,x2,y2){
    // Simple line slice - returns two polygons
    console.log('Polygon slice at', x1,y1,x2,y2);
    return [this, new R.Polygon(this.kianja, this.points, {x:this.x, y:this.y, loko:'#ff1493'})];
  };
  
  R.Polygon.prototype.contains = function(x,y){
    // Ray casting algorithm
    var inside = false;
    for(var i=0,j=this.points.length-1; i<this.points.length; j=i++){
      var xi = this.points[i].x + this.x, yi = this.points[i].y + this.y;
      var xj = this.points[j].x + this.x, yj = this.points[j].y + this.y;
      var intersect = ((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
      if(intersect) inside = !inside;
    }
    return inside;
  };
  
  R.Polygon.prototype.havaozy = function(dt){
    if(this.havaozyKoa) this.havaozyKoa(dt);
  };
  
  R.Polygon.prototype.soraty = function(ctx){
    if(!ctx || this.points.length < 2) return;
    ctx.save();
    ctx.fillStyle = this.loko;
    ctx.strokeStyle = this.stroke;
    ctx.lineWidth = this.lineWidth;
    ctx.beginPath();
    ctx.moveTo(this.points[0].x + this.x, this.points[0].y + this.y);
    for(var i=1; i<this.points.length; i++){
      ctx.lineTo(this.points[i].x + this.x, this.points[i].y + this.y);
    }
    ctx.closePath();
    if(this.fill) ctx.fill();
    ctx.stroke();
    ctx.restore();
  };
  
  // Alias for compatibility
  R.PolygonSlice = R.Polygon;
  
  console.log('✅ rakitrakatra.polygon.min.js FIXED');
})();
